const totalSize = allFiles.reduce((sum, f) => sum + f.size, 0);
const byExt = {};
for (const f of allFiles) {
  const ext = path.extname(f.path);
  byExt[ext] = (byExt[ext] || 0) + 1;
}

console.log('Found', allFiles.length, 'files,', totalSize, 'bytes');
